// // This module inverts the input A when TE is low, otherwise it passes through A.
module my_inverter (
    input  A   ,
    output Z   ,
    input  TE  ,
    input  VPB ,
    input  VPWR,
    input  VGND,
    input  VNB
);

  wire A_bar;
  assign A_bar = ~A;

  assign Z = TE ? A_bar : A;

endmodule
